2️⃣ 事务日志 & 撤销功能

class TransactionManager {
private commands: Command[] = [];
execute(command: Command): void {
command.execute();
this.commands.push(command);
}
undoAll(): void {
// 倒序撤销所有命令
for (let i = this.commands.length - 1; i >= 0; i--) {
this.commands[i].undo();
}
this.commands = [];
}
}

