3️⃣ 宏命令（批量操作）

class MacroCommand implements Command {
private commands: Command[] = [];
add(command: Command): void {
this.commands.push(command);
}
execute(): void {
this.commands.forEach(cmd => cmd.execute());
}
undo(): void {
this.commands.forEach(cmd => cmd.undo());
}
}

