4️⃣ 异步任务队列

class TaskQueue {
private queue: Command[] = [];
addTask(command: Command): void {
this.queue.push(command);
}
async processAll(): Promise<void> {
while (this.queue.length > 0) {
const command = this.queue.shift()!;
await command.executeAsync();
}
}
}

